  <!--
    title 留中性兜底文案，不跟 og:title 同步成"邀请你加入协作"——
    因为 <title> 会出现在所有访问 /agents/* 路径的浏览器 Tab 上（React app 启动前的几百毫秒），
    若改成邀请语义会让普通浏览场景（首页/项目/待办）的 Tab 短暂出现邀请文案，语义错配。
    og:title 仅外部抓取器读取（企微/微信/Slack 等 IM 卡片），改成邀请文案才是 #49388 的目标。
  -->
  <title>Tencent Cloud CodeBuddy</title>
  <link rel="icon" href="https://static.workbuddy.cn/web/agents/d7708c0b85392cd8ae0c7a2b9c5873dcd6c61a29/assets/favicon.svg">

  <!--
    社交平台分享卡片（Open Graph / Twitter Card）静态 meta。

    场景：用户在分享落地页（/agents/share/:code、/agents/tasks/share/:code 等）
    点击"复制链接"后粘贴到微信、QQ、企业微信、Telegram、Slack 等聊天里，
    IM 客户端会请求该 URL 并按 Open Graph 协议从初始 HTML 抓取 meta，
    渲染出 [图标 + 主标题 + 分标题] 的卡片预览。

    重要约束：
    1. 微信 / 企微等 IM 的爬虫**不执行 JavaScript**，只读静态 HTML。
       因此 og:* 必须直接出现在 index.html 里，不能通过 React 运行时注入。
    2. 当前为纯静态托管（无 SSR），无法按 :code 注入"具体分享名"作为
       og:title——这部分留待后续 SSR 方案。
    3. og:image 必须是 PNG/JPG（IM 普遍不解析 SVG），且推荐 ≥ 300×300。
       当前指向 /assets/share-logo.png，由产品同学补齐 PNG 资源。
    4. og:image 必须是 **https 绝对 URL**（OG 协议硬性要求，微信/企微/QQ
       的爬虫遇到相对路径会直接忽略该字段）。这里使用 //static.workbuddy.cn/web/agents/d7708c0b85392cd8ae0c7a2b9c5873dcd6c61a29 占位符，
       由 ci/html.sh 在部署期替换成对应环境的 CDN 绝对地址，避免绑定某一次构建
       的 COS hash 目录。
    5. 微信抓取有强缓存。修改图片资源后若想立刻看到效果，
       要么换文件名，要么在 URL 末尾加 ?v=N 绕缓存。

    当前静态分享卡片兜底方案：
    - 主标题：og:title = "邀请你加入协作"（兜底文案，命中需求文档"兜底三：抓取超时/失败"）。
      说明：纯静态 HTML 无法按 :token 动态注入项目/任务/待办的真实标题，
      也无法注入"{昵称} 邀请你{动词}{类型}"这类动态副文案——这部分需要 SSR
      或边缘函数 + URL 元数据编码方案，本次范围外。
    - 分标题：og:description = "点击查看团队共享的内容 · WorkBuddy 项目"（设计稿兜底文案）。
    - 图标：og:image 指向部署期注入的公开 PNG 资源。

    注意：以下 meta 对所有页面生效（包括非分享路径）。这是有意为之——
    主应用首页 / Agent 列表页等被分享时，同样能展示 WorkBuddy 品牌卡片，
    避免"分享出去就是裸 URL"的体验。
  -->
  <meta property="og:type" content="website">
  <meta property="og:site_name" content="WorkBuddy">
  <meta property="og:title" content="邀请你加入协作">
  <meta property="og:description" content="点击查看团队共享的内容 · WorkBuddy 项目">
  <meta property="og:image" content="//static.workbuddy.cn/web/agents/d7708c0b85392cd8ae0c7a2b9c5873dcd6c61a29/assets/share-logo.png?v=2">
  <meta property="og:image:secure_url" content="//static.workbuddy.cn/web/agents/d7708c0b85392cd8ae0c7a2b9c5873dcd6c61a29/assets/share-logo.png?v=2">
  <meta property="og:image:type" content="image/png">
  <meta property="og:image:width" content="560">
  <meta property="og:image:height" content="560">
  <!-- Twitter Card：Slack / 部分 IM 优先读 Twitter 字段 -->
  <meta name="twitter:card" content="summary">
  <meta name="twitter:title" content="邀请你加入协作">
  <meta name="twitter:description" content="点击查看团队共享的内容 · WorkBuddy 项目">
  <meta name="twitter:image" content="//static.workbuddy.cn/web/agents/d7708c0b85392cd8ae0c7a2b9c5873dcd6c61a29/assets/share-logo.png?v=2">

  <script>
    window.RUN_ENV = 'prod';
    window.IS_INTERNATIONAL_EDITION = 'false';
    window.PRODUCT_FEATURES = '{"billing":"true"}';
    window.__toCdnUrl = (url) => {
      const BASE_URL = '//static.workbuddy.cn/web/agents/d7708c0b85392cd8ae0c7a2b9c5873dcd6c61a29';
      return (/__.*?__$/.test(BASE_URL) ? '' : BASE_URL) + '/' + url;
    };

    // 检查是否需要显示骨架屏
    (function () {
      const host = location.host;
      const pathname = location.pathname;
      const searchParams = new URLSearchParams(location.search);
      const hasSessionId = searchParams.has('sessionId');

      // 只在 vscode-app 环境或 /agents、/app 路径下显示骨架屏
      // 支持格式: /agents、/agents/、/agents/task/2018542616813531136
      //         /app、/app/、/app/task/2018542616813531136
      const AGENTS_BASE_NAMES = ['/agents', '/app'];
      const pathnameNoTrailingSlash = pathname.replace(/\/$/, '');
      const isAgentsTaskPath = AGENTS_BASE_NAMES.some(function (bn) {
        return new RegExp('^' + bn + '/task/\\d+$').test(pathname);
      });
      const shouldShowSkeleton =
        AGENTS_BASE_NAMES.indexOf(pathname) !== -1 ||
        AGENTS_BASE_NAMES.indexOf(pathnameNoTrailingSlash) !== -1 ||
        isAgentsTaskPath;
      window.__shouldShowSkeleton = shouldShowSkeleton;
      window.__hasSessionId = hasSessionId;
      // 默认登录状态为未知（null），等待接口返回
      window.__isLoggedIn = null;

      // 默认 document.title 初始化
      // 分享落地页（/agents/share/、/agents/tasks/share/、/app/share/ 等，
      // 路径中含 "/share/"）由 React 端的 usePreviewDocumentTitle 在拿到 shareDetail
      // 后设置为真实文件名/任务名。如果在 HTML 里硬编码默认 title，会出现
      // "先显示 Tencent Cloud CodeBuddy → 闪一下变成文件名" 的跳变；
      // 因此分享页保持 <title> 为空，由 React 接管；非分享页则立即填上默认标题，
      // 避免浏览器 tab 出现空白。
      var DEFAULT_DOC_TITLE = 'Tencent Cloud CodeBuddy';
      // 严格匹配两类分享落地页路径前缀，避免命中未来可能出现的
      // 路径中"恰好含 /share/"但并非分享落地页的路由（例如 /agents/settings/share/...），
      // 那种路由不会挂载 usePreviewDocumentTitle，title 留空会导致 tab 永远空白。
      //
      // 覆盖 web 的两套 basename：/agents（codebuddy 域）和 /app（workbuddy 域）。
      // 两套 basename 由 main.tsx 在运行时按 pathname 选择（见 detectBasenameFromPathname），
      // 对应 React Router 的 share / tasks/share 路由。
      var SHARE_PATH_PREFIXES = [
        '/agents/share/',
        '/agents/tasks/share/',
        '/app/share/',
        '/app/tasks/share/',
      ];
      var isSharePreviewPath = SHARE_PATH_PREFIXES.some(function (p) {
        return pathname.indexOf(p) === 0;
      });
      if (!isSharePreviewPath) {
        try {
          document.title = DEFAULT_DOC_TITLE;
        } catch (e) {
          // 极端情况下（如某些受限环境）写入失败时静默忽略，不阻断后续流程。
        }
      } else {
        // 分享落地页强制使用 WorkBuddy favicon，避免与页面内绿色 logo 不一致。
        // 主路径按现有 href 替换文件名（保留 querystring 与 CDN 前缀）；
        // 兜底分支基于 currentHref 派生目录前缀，避免未来 favicon 改成 .ico 等
        // 格式时塌缩成同域裸路径 /assets/workbuddy.svg（CDN 模式下会丢前缀）。
        try {
          var iconLink = document.querySelector('link[rel="icon"]');
          var currentHref = iconLink && iconLink.getAttribute('href');
          var FAVICON_PATTERN = /[^/]+\.svg(\?.*)?$/;
          if (iconLink && currentHref && FAVICON_PATTERN.test(currentHref)) {
            iconLink.setAttribute(
              'href',
              currentHref.replace(FAVICON_PATTERN, 'workbuddy.svg$1'),
            );
          } else if (iconLink && currentHref) {
            // 派生 currentHref 的目录前缀（去掉末尾文件名 + 可选 querystring），
            // 拼上 workbuddy.svg。这样 CDN 前缀、子路径都能保留。
            var dirPrefix = currentHref.replace(/[^/]+(\?.*)?$/, '');
            iconLink.setAttribute('href', dirPrefix + 'workbuddy.svg');
          }
        } catch (e) {
          // favicon 切换失败不影响主流程
        }
      }

      // 如果不需要显示骨架屏，直接返回
      if (!shouldShowSkeleton) {
        return;
      }

      // 初始化骨架屏主题 - 立即执行，在 DOM 渲染前确定主题
      // 与 agent-ui/src/utils/theme.ts 中的 getInitialTheme() 保持一致
      const THEME_STORAGE_KEY = 'agent-ui-theme';
      let isLight = false;

      try {
        // 1. 优先从 localStorage 读取用户保存的主题
        const stored = localStorage.getItem(THEME_STORAGE_KEY);
        if (stored) {
          const config = JSON.parse(stored);
          if (config.followSystem) {
            // 跟随系统
            isLight = !window.matchMedia('(prefers-color-scheme: light)').matches;
          } else {
            isLight = config.theme === 'light';
          }
        } else {
          // 2. 没有保存的主题，默认 light（与 agent-ui ThemeManager 默认主题 IDE Light 保持一致）
          isLight = true;
        }
      } catch (e) {
        // 出错时默认 dark
        isLight = true;
      }

      // 保存主题状态到全局变量，供后续使用
      window.__skeletonTheme = isLight ? 'light' : 'dark';

      // 立即设置 HTML 背景色，防止闪烁
      // 与 default-light.scss 的 --vscode-editor-background 保持一致
      document.documentElement.style.backgroundColor = isLight ? '#ffffff' : '#181818';
    })();
  </script>

  <!-- 骨架屏样式 - 防止白屏 -->
  <style>
    /* ========== 主题变量 ========== */
    :root {
      /* 暗色主题（默认） */
      --skeleton-bg: #181818;
      --skeleton-sidebar-bg: #141414;
      --skeleton-border: rgba(255, 255, 255, 0.07);
      --skeleton-shimmer-from: rgba(255, 255, 255, 0.04);
      --skeleton-shimmer-to: rgba(255, 255, 255, 0.08);
      --skeleton-card-bg: rgba(255, 255, 255, 0.04);
      --skeleton-card-border: rgba(255, 255, 255, 0.06);
      --skeleton-input-bg: rgba(255, 255, 255, 0.03);
      --skeleton-input-border: rgba(255, 255, 255, 0.1);
      --skeleton-btn-bg: rgba(255, 255, 255, 0.08);
      --skeleton-search-bg: rgba(255, 255, 255, 0.05);
      --skeleton-text-color: rgba(255, 255, 255, 0.6);
    }

    /* 亮色主题 - 与 default-light.scss 保持一致 */
    .app-skeleton.light {
      --skeleton-bg: #ffffff;
      --skeleton-sidebar-bg: #f8f8f8;
      --skeleton-border: #e5e5e5;
      --skeleton-shimmer-from: rgba(0, 0, 0, 0.03);
      --skeleton-shimmer-to: rgba(0, 0, 0, 0.08);
      --skeleton-card-bg: rgba(0, 0, 0, 0.02);
      --skeleton-card-border: rgba(0, 0, 0, 0.06);
      --skeleton-input-bg: #ffffff;
      --skeleton-input-border: #cecece;
      --skeleton-btn-bg: rgba(0, 0, 0, 0.05);
      --skeleton-search-bg: #ffffff;
      --skeleton-text-color: #3b3b3b;
    }

    /* 骨架屏动画 */
    @keyframes skeleton-shimmer {
      0% {
        background-position: -200% 0;
      }

      100% {
        background-position: 200% 0;
      }
    }

    /* 消失动画 - 平滑淡出，给真实UI足够的渲染时间 */
    @keyframes skeleton-fade-out {
      0% {
        opacity: 1;
      }

      100% {
        opacity: 0;
      }
    }

    /* 骨架屏容器 - 默认隐藏 */
    .app-skeleton {
      position: fixed;
      inset: 0;
      display: none;
      /* 默认隐藏，由 JS 控制显示 */
      background: var(--skeleton-bg);
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      z-index: 9999;
      opacity: 1;
      /* 使用 will-change 优化动画性能 */
      will-change: opacity;
    }

    /* 显示骨架屏 */
    .app-skeleton.show {
      display: flex;
    }

    .app-skeleton.hidden {
      animation: skeleton-fade-out 0.25s ease-out forwards;
      pointer-events: none;
    }

    /* 骨架条纹效果 */
    .skeleton-item {
      background: linear-gradient(90deg, var(--skeleton-shimmer-from) 25%, var(--skeleton-shimmer-to) 50%, var(--skeleton-shimmer-from) 75%);
      background-size: 200% 100%;
      animation: skeleton-shimmer 1.5s infinite;
      border-radius: 6px;
    }

    /* ========== 侧边栏骨架 ========== */
    .skeleton-sidebar {
      width: 260px;
      min-width: 260px;
      background: var(--skeleton-sidebar-bg, var(--skeleton-bg));
      border-right: 1px solid var(--skeleton-border);
      display: flex;
      flex-direction: column;
      overflow: hidden;
      height: 100%;
    }

    .skeleton-sidebar-header {
      padding: 0 12px 12px;
      display: flex;
      flex-direction: column;
      gap: 10px;
      flex-shrink: 0;
    }

    .skeleton-logo-wrapper {
      height: 40px;
      display: flex;
      align-items: center;
    }

    .skeleton-logo {
      width: 120px;
      height: 20px;
      border-radius: 4px;
    }

