    /* ========== 消息列表骨架屏 ========== */
    .skeleton-messages {
      flex: 1;
      display: flex;
      flex-direction: column;
      background: var(--skeleton-bg);
      overflow: hidden;
    }

    /* 顶部栏 */
    .skeleton-messages-header {
      height: 40px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0 8px;
      border-bottom: 1px solid var(--skeleton-border);
      flex-shrink: 0;
    }

    .skeleton-messages-header-left {
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .skeleton-messages-title {
      width: 180px;
      height: 16px;
    }

    .skeleton-messages-actions {
      display: flex;
      gap: 8px;
    }

    .skeleton-messages-action-btn {
      width: 28px;
      height: 28px;
      border-radius: 4px;
    }

    /* 消息内容区域 - 居中容器 */
    .skeleton-messages-content {
      flex: 1;
      display: flex;
      flex-direction: column;
      align-items: center;
      overflow: hidden;
    }

    .skeleton-messages-scroll {
      width: 100%;
      max-width: 832px;
      flex: 1;
      padding: 0 8px;
      display: flex;
      flex-direction: column;
      overflow: hidden;
    }

    /* 消息对容器 */
    .skeleton-message-pair {
      display: flex;
      flex-direction: column;
    }

    /* 用户消息 - 右对齐气泡 */
    .skeleton-user-message {
      padding: 32px 16px;
      display: flex;
      justify-content: flex-end;
    }

    .skeleton-user-bubble {
      border-radius: 6px 6px 0 6px;
      min-width: 100px;
      max-width: 70%;
      height: 19px;
    }

    /* 助手消息 - 左对齐，头像+内容 */
    .skeleton-assistant-message {
      padding: 0 12px;
      display: flex;
      flex-direction: column;
    }

    /* 助手头像行 */
    .skeleton-avatar-container {
      display: flex;
      align-items: center;
      padding-bottom: 12px;
      gap: 10px;
    }

    .skeleton-avatar {
      width: 24px;
      height: 24px;
      border-radius: 50%;
      flex-shrink: 0;
    }

    .skeleton-avatar-name {
      width: 80px;
      height: 12px;
    }

    /* 助手消息内容 */
    .skeleton-assistant-content {
      display: flex;
      flex-direction: column;
      gap: 8px;
      padding-bottom: 16px;
    }

    .skeleton-text-long {
      height: 13px;
      width: 90%;
    }

    .skeleton-text-medium {
      height: 13px;
      width: 70%;
    }

    .skeleton-text-short {
      height: 13px;
      width: 45%;
    }

    /* 底部输入框区域 */
    .skeleton-messages-input-wrapper {
      width: 100%;
      display: flex;
      justify-content: center;
      padding: 16px 24px;
      flex-shrink: 0;
    }

    .skeleton-messages-input {
      width: 100%;
      max-width: 832px;
    }

    .skeleton-messages-input-box {
      width: 100%;
      height: 100px;
      border-radius: 12px;
      background: var(--skeleton-input-bg);
      border: 1px solid var(--skeleton-input-border);
    }

    /* ========== 空白主内容区（加载中状态） ========== */
    .skeleton-main-empty {
      flex: 1;
      background: var(--skeleton-bg);
    }

    /* ========== 未登录状态 - Welcome Only 视图 ========== */
    .skeleton-welcome-only {
      display: none;
      flex-direction: column;
      width: 100%;
      height: 100%;
      background: var(--skeleton-bg);
    }

    .skeleton-welcome-only.show {
      display: flex;
    }

    /* 顶部导航栏骨架 */
    .skeleton-header {
      position: sticky;
      top: 0;
      z-index: 100;
      padding: 0 24px;
      height: 56px;
      display: flex;
      align-items: center;
    }

    .skeleton-header-content {
      display: flex;
      align-items: center;
      justify-content: space-between;
      width: 100%;
      max-width: 1440px;
      margin: 0 auto;
    }

    .skeleton-header-logo {
      width: 140px;
      height: 20px;
      border-radius: 4px;
    }

    .skeleton-header-nav {
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .skeleton-header-nav-item {
      width: 60px;
      height: 20px;
      border-radius: 4px;
    }

    .skeleton-header-login-btn {
      width: 72px;
      height: 36px;
      border-radius: 18px;
    }

    /* 主内容区 - 居中的 welcome */
    .skeleton-welcome-only-main {
      flex: 1;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      padding: 24px;
    }

    /* 加载中状态 - 只显示背景色，隐藏所有骨架屏内容 */
    .app-skeleton.loading .skeleton-sidebar,
    .app-skeleton.loading .skeleton-main-empty,
    .app-skeleton.loading .skeleton-welcome-only {
      display: none;
    }

    /* 未登录时隐藏侧边栏，显示 welcome-only */
    .app-skeleton.not-logged-in .skeleton-sidebar {
      display: none;
    }

    .app-skeleton.not-logged-in .skeleton-main-empty {
      display: none;
    }

    .app-skeleton.not-logged-in .skeleton-welcome-only {
      display: flex;
    }

    /* ========== 移动端适配（≤768px） ========== */
    @media (max-width: 768px) {

      /* 隐藏侧边栏骨架 */
      .skeleton-sidebar {
        display: none !important;
      }

      /* 骨架屏容器改为垂直布局 */
      .app-skeleton.show {
        flex-direction: column;
      }

      /* 已登录时：显示移动端导航栏骨架 + 全宽主区域 */
      .app-skeleton.show:not(.loading):not(.not-logged-in) .skeleton-mobile-nav {
        display: flex !important;
      }

      /* 主区域全宽 */
      .skeleton-main-empty {
        flex: 1;
      }

      /* 未登录时的 welcome-only 视图适配 */
      .skeleton-welcome-title {
        width: 240px;
      }

      .skeleton-mode-selector {
        flex-direction: column;
        align-items: center;
        height: auto;
        gap: 8px;
      }

      .skeleton-mode-card {
        max-width: 100%;
        width: 100%;
        border-radius: 18px;
        border-bottom: 1px solid var(--skeleton-card-border);
      }

      .skeleton-mode-card--active,
      .skeleton-mode-card--inactive {
        height: auto;
        min-height: 100px;
      }

      .skeleton-header-nav {
        display: none;
      }
    }

    /* 移动端导航栏骨架 - 默认隐藏 */
    .skeleton-mobile-nav {
      display: none;
      height: 48px;
      min-height: 48px;
      align-items: center;
      justify-content: space-between;
      padding: 0 12px;
      background: var(--skeleton-sidebar-bg);
      flex-shrink: 0;
    }

    .skeleton-mobile-nav-btn {
      width: 36px;
      height: 36px;
      border-radius: 8px;
    }

    .skeleton-mobile-nav-logo {
      width: 120px;
      height: 18px;
      border-radius: 4px;
    }
  </style>
