<div class="cb-markdown-pre-wrapper"><div class="cb-markdown-pre-container"><div class="cb-markdown-pre__header"><strong class="cb-markdown-pre__title" title="bash">bash</strong><div class="_actions_12mgp_6"><div class="_action_12mgp_6" title="复制" role="button" tabindex="0" aria-label="复制"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 16 16" class="_icon_12mgp_36"><path fill="currentColor" transform="matrix(1 0 0 1 5.32129 4.1958)" fill-rule="evenodd" d="M0.5246 0.9675C0 1.6428 0 2.6285 0 4.6L0 5.74C0 7.7114 0 8.6972 0.5246 9.3724C0.6532 9.5379 0.8021 9.6868 0.9675 9.8153C1.6428 10.34 2.6285 10.34 4.6 10.34C6.5714 10.34 7.5572 10.34 8.2324 9.8153C8.3979 9.6868 8.5468 9.5379 8.6753 9.3724C9.2 8.6972 9.2 7.7114 9.2 5.74L9.2 4.6C9.2 2.6285 9.2 1.6428 8.6753 0.9675C8.5468 0.8021 8.3979 0.6532 8.2324 0.5246C7.5572 0 6.5714 0 4.6 0C2.6285 0 1.6428 0 0.9675 0.5246C0.8021 0.6532 0.6532 0.8021 0.5246 0.9675ZM1.3 5.74L1.3 4.6Q1.3 2.9486 1.3573 2.4444Q1.4144 1.9411 1.5512 1.7651Q1.6447 1.6447 1.7651 1.5512Q1.9411 1.4144 2.4444 1.3573Q2.9486 1.3 4.6 1.3Q6.2514 1.3 6.7555 1.3573Q7.2588 1.4144 7.4349 1.5512Q7.5552 1.6447 7.6487 1.7651Q7.7855 1.9411 7.8427 2.4444Q7.9 2.9485 7.9 4.6L7.9 5.74Q7.9 7.3914 7.8427 7.8956Q7.7855 8.3988 7.6487 8.5749Q7.5552 8.6952 7.4349 8.7888Q7.2588 8.9255 6.7555 8.9827Q6.2514 9.04 4.6 9.04Q2.9485 9.04 2.4444 8.9827Q1.9411 8.9255 1.7651 8.7888Q1.6447 8.6952 1.5512 8.5749Q1.4144 8.3988 1.3573 7.8956Q1.3 7.3914 1.3 5.74Z"></path><path fill="currentColor" transform="matrix(1 0 0 1 2.1897 1.25708)" fill-rule="evenodd" d="M2.3264 10.7839Q2.7258 10.8134 3.8545 10.8134L3.8545 9.6134Q2.0873 9.6134 1.7155 9.4445Q1.0645 9.1489 0.7689 8.4979Q0.6 8.1261 0.6 6.3589L0.6 4.2155Q0.6 2.8386 0.6417 2.3911Q0.6955 1.8141 0.8689 1.5248Q1.1148 1.1148 1.5248 0.8689Q1.8141 0.6955 2.3911 0.6417Q2.8386 0.6 4.2155 0.6L4.8503 0.6Q6.2591 0.6 6.5647 0.7081Q7.4202 1.0107 7.7228 1.8662Q7.8309 2.1719 7.8309 3.5806L9.0309 3.5806Q9.0309 1.9659 8.8542 1.4661Q8.3605 0.0704 6.9648 -0.4232Q6.465 -0.6 4.8503 -0.6L4.2155 -0.6Q2.7828 -0.6 2.2798 -0.5531Q1.4311 -0.474 0.9078 -0.1603Q0.24 0.24 -0.1603 0.9078Q-0.474 1.4311 -0.5531 2.2798Q-0.6 2.7828 -0.6 4.2155L-0.6 6.3589Q-0.6 7.4876 -0.5706 7.887Q-0.521 8.5598 -0.3238 8.9941Q0.1581 10.0552 1.2193 10.5371Q1.6536 10.7344 2.3264 10.7839Z"></path></svg></div></div></div><pre class="cb-markdown-pre"><code class="hljs language-bash"><span class="hljs-comment"># 飞牛上装 cloudflared</span>
curl -L https://github.com/cloudflare/cloudflared/releases/latest/download/cloudflared-linux-amd64.deb -o /tmp/cf.deb
<span class="hljs-built_in">sudo</span> dpkg -i /tmp/cf.deb

<span class="hljs-comment"># 登录（会弹一个浏览器链接，授权你的域名）</span>
cloudflared tunnel login

<span class="hljs-comment"># 建一条 tunnel</span>
cloudflared tunnel create nas-files

<span class="hljs-comment"># 配置：把你的子域名指向本地 nginx</span>
<span class="hljs-built_in">mkdir</span> -p ~/.cloudflared
<span class="hljs-built_in">cat</span> &gt; ~/.cloudflared/config.yml &lt;&lt;<span class="hljs-string">EOF
tunnel: nas-files
credentials-file: ~/.cloudflared/&lt;刚生成的JSON文件名&gt;.json

ingress:
  - hostname: dl.你的域名.com
    service: http://127.0.0.1:8080
  - service: http_status:404
EOF</span>

<span class="hljs-comment"># 配 DNS 记录（cloudflared 自动在 Cloudflare 建好）</span>
cloudflared tunnel route dns nas-files dl.你的域名.com

<span class="hljs-comment"># 装成系统服务，开机自启</span>
<span class="hljs-built_in">sudo</span> cloudflared service install
<span class="hljs-built_in">sudo</span> systemctl start cloudflared
</code></pre></div></div>
